Bash(docker compose -f /Volumes/DATA/UIT/PROJECTS/learning_data_system/docker-compose.yml exec -T postgres psql -U postgres -d learning_data_system -c "
SELECT COUNT\(*\) AS attendance_distributed FROM attendance_distributed;
SELECT COUNT\(*\) AS student_sensitive FROM student_sensitive;
SELECT COUNT\(*\) AS course_prerequisites FROM course_prerequisites;
" 2>&1)

Bash(docker exec t3h_postgres psql -U postgres -d learning_data_system -c "
-- Check FTS columns \(tsvector\) và triggers liên quan FTS
SELECT tablename, attname FROM pg_attribute a
JOIN pg_class c ON a.attrelid = c.oid
JOIN pg_namespace n ON c.relnamespace = n.oid
WHERE n.nspname='public' AND atttypid = 'tsvector'::regtype AND NOT attisdropped;
" 2>&1 && docker exec t3h_postgres psql -U postgres -d learning_data_system -c "
SELECT tgname, relname FROM pg_trigger t JOIN pg_class c ON t.tgrelid=c.oid WHERE NOT tgisinternal ORDER BY relname;
" 2>&1 && docker exec t3h_postgres psql -U postgres -d learning_data_system -c "
-- Kiểm tra student_locations \(Spatial\) và branches geom
SELECT COUNT\(*\) as student_locations_count FROM student_locations;
SELECT COUNT\(*\) as branches_with_geom FROM branches WHERE geom IS NOT NULL;
SELECT COUNT\(*\) as course_materials_count FROM course_materials;
SELECT COUNT\(*\) as prerequisites_count FROM course_prerequisites;
" 2>&1)
